module top_module(
  input signed [31:0] obf_a,
  input signed [31:0] b,
  input [1:0] op,
  output reg signed [31:0] result
);always @(*) begin
    case(op)
      2'b00: result = obf_a + b;
      2'b01: result = obf_a - b;
      2'b10: result = obf_a * b;
      2'b11: result = obf_a / b;
    endcase
  end

endmodule
